function buildResultMessage(result, examName, schoolName) {
  const total = result.subjects.reduce((s2, r2) => s2 + r2.marksObtained, 0);
  const maxTotal = result.subjects.reduce((s2, r2) => s2 + r2.maxMarks, 0);
  const pct2 = maxTotal > 0 ? Math.round(total / maxTotal * 100) : 0;
  const grade = calcGrade(pct2);
  const subjectLines = result.subjects.map((s2) => {
    const sp = s2.maxMarks > 0 ? Math.round(s2.marksObtained / s2.maxMarks * 100) : 0;
    return `  ${s2.subject.padEnd(14, " ")} ${String(s2.marksObtained).padStart(3)}/${s2.maxMarks}  ${calcGrade(sp)}`;
  }).join("\n");
  return `📊 *Result Card - ${schoolName}*

Dear Parent,

*${result.studentName}* | Adm No: ${result.admNo}
*Exam:* ${examName}

${"─".repeat(34)}
*Subject*       *Marks*  *Grade*
${"─".repeat(34)}
${subjectLines}
${"─".repeat(34)}
*Total:* ${total}/${maxTotal}  *Overall:* ${grade}  *%:* ${pct2}%
*Result:* ${pct2 >= 40 ? "✅ PASS" : "❌ FAIL"}

${schoolName}`;
}
function exportToExcel(group) {
  const headers = [
    "Student",
    "Adm. No.",
    ...group.subjects,
    "Total",
    "%",
    "Grade",
    "Result"
  ];
  const rows = group.studentResults.map((r2) => {
    const total = r2.subjects.reduce((s2, sub) => s2 + sub.marksObtained, 0);
    const maxTotal = r2.subjects.reduce((s2, sub) => s2 + sub.maxMarks, 0);
    const pct2 = maxTotal > 0 ? Math.round(total / maxTotal * 100) : 0;
    return [
      r2.studentName,
      r2.admNo,
      ...r2.subjects.map((s2) => s2.marksObtained),
      `${total}/${maxTotal}`,
      `${pct2}%`,
      calcGrade(pct2),
      pct2 >= 40 ? "PASS" : "FAIL"
    ];
  });
  const csv = [headers, ...rows].map((r2) => r2.map((c2) => `"${c2}"`).join(",")).join("\n");
  const blob = new Blob([csv], { type: "text/csv" });
  const url = URL.createObjectURL(blob);
  const a2 = document.createElement("a");
  a2.href = url;
  a2.download = `${group.examName}_${group.classKey}_results.csv`.replace(
    /\s+/g,
    "_"
  );
  a2.click();
  URL.revokeObjectURL(url);
}
